const CACHE_NAME = 'firetrack-v1';
const ASSETS = [
  '/',
  '/index.html',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

export enum VehicleStatus {
  AVAILABLE = 'Available',
  OUT_ON_CALL = 'Out on Call',
  MAINTENANCE = 'Maintenance',
  OUT_OF_SERVICE = 'Out of Service'
}

export enum VehicleType {
  ENGINE = 'Engine (Pumper)',
  LADDER = 'Ladder Truck',
  TANKER = 'Tanker',
  RESCUE = 'Rescue Unit',
  COMMAND = 'Command Vehicle'
}

export interface Equipment {
  id: string;
  name: string;
  category: string;
  quantity: number;
  lastChecked: string;
  condition: 'Good' | 'Fair' | 'Poor' | 'Needs Replacement';
}

export interface Vehicle {
  id: string;
  callSign: string;
  type: VehicleType;
  status: VehicleStatus;
  mileage: number;
  location: string;
  lastService: string;
  crewCapacity: number;
  equipment: Equipment[];
}

export interface FleetStats {
  totalVehicles: number;
  available: number;
  maintenance: number;
  outOnCall: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Vehicle } from "../types";

export const analyzeFleetStatus = async (vehicles: Vehicle[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `As a Fire Department Fleet Analyst, analyze the following fleet inventory and provide a concise summary of readiness, potential maintenance risks, and resource allocation recommendations:
  ${JSON.stringify(vehicles, null, 2)}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a professional Fire Chief Fleet Advisor. Be concise, safety-oriented, and professional."
      }
    });
    return response.text || "Unable to generate analysis at this time.";
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "Fleet analysis service temporarily unavailable.";
  }
};

import React from 'react';
import { Vehicle, VehicleStatus } from '../types';

interface DashboardProps {
  vehicles: Vehicle[];
}

const Dashboard: React.FC<DashboardProps> = ({ vehicles }) => {
  const stats = {
    total: vehicles.length,
    available: vehicles.filter(v => v.status === VehicleStatus.AVAILABLE).length,
    maintenance: vehicles.filter(v => v.status === VehicleStatus.MAINTENANCE).length,
    outOnCall: vehicles.filter(v => v.status === VehicleStatus.OUT_ON_CALL).length,
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
      <StatCard label="Total Fleet" value={stats.total} color="bg-gray-100 text-gray-800" />
      <StatCard label="Ready/Available" value={stats.available} color="bg-green-100 text-green-800" />
      <StatCard label="In Shop" value={stats.maintenance} color="bg-orange-100 text-orange-800" />
      <StatCard label="Active Calls" value={stats.outOnCall} color="bg-red-100 text-red-800" />
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: number; color: string }> = ({ label, value, color }) => (
  <div className={`p-4 rounded-xl shadow-sm ${color} border border-opacity-10 flex flex-col items-center justify-center transition-transform hover:scale-105`}>
    <span className="text-3xl font-bold">{value}</span>
    <span className="text-xs uppercase tracking-wider font-semibold opacity-70">{label}</span>
  </div>
);

export default Dashboard;

import React from 'react';
import { Vehicle, VehicleStatus } from '../types';

interface VehicleCardProps {
  vehicle: Vehicle;
  onSelect: (v: Vehicle) => void;
}

const VehicleCard: React.FC<VehicleCardProps> = ({ vehicle, onSelect }) => {
  const getStatusColor = (status: VehicleStatus) => {
    switch (status) {
      case VehicleStatus.AVAILABLE: return 'bg-green-500';
      case VehicleStatus.OUT_ON_CALL: return 'bg-red-500';
      case VehicleStatus.MAINTENANCE: return 'bg-orange-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div 
      onClick={() => onSelect(vehicle)}
      className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 cursor-pointer hover:shadow-md transition-shadow relative overflow-hidden group"
    >
      <div className={`absolute left-0 top-0 bottom-0 w-1 ${getStatusColor(vehicle.status)}`} />
      <div className="flex justify-between items-start">
        <div>
          <h3 className="text-lg font-bold text-gray-900 group-hover:text-red-600 transition-colors">
            {vehicle.callSign}
          </h3>
          <p className="text-sm text-gray-500">{vehicle.type}</p>
        </div>
        <span className={`px-2 py-1 rounded-full text-[10px] font-bold text-white uppercase ${getStatusColor(vehicle.status)}`}>
          {vehicle.status}
        </span>
      </div>

      <div className="mt-4 grid grid-cols-2 gap-2 text-xs text-gray-600">
        <div className="flex items-center space-x-1">
          <span className="font-semibold">Loc:</span>
          <span>{vehicle.location}</span>
        </div>
        <div className="flex items-center space-x-1">
          <span className="font-semibold">Miles:</span>
          <span>{vehicle.mileage.toLocaleString()}</span>
        </div>
      </div>

      <div className="mt-3 flex items-center text-[11px] text-gray-400 border-t pt-2">
        <span>Last Service: {vehicle.lastService}</span>
      </div>
    </div>
  );
};

export default VehicleCard;

import React, { useState } from 'react';
