          <div>
            <h1 className="text-3xl font-black tracking-tighter uppercase">FireTrack Pro</h1>
            <p className="text-xs opacity-75 font-medium tracking-widest uppercase mt-1">Central Fleet Command</p>
          </div>
          <button 
            onClick={triggerFleetAnalysis}
            disabled={isAnalyzing}
            className="bg-white/20 hover:bg-white/30 backdrop-blur-md px-4 py-2 rounded-lg text-sm font-bold flex items-center space-x-2 transition-all active:scale-95 disabled:opacity-50"
          >
