                    <label className="text-[10px] font-black text-gray-400 uppercase">Category</label>
                    <select 
                      value={filterCategory} 
                      onChange={(e) => setFilterCategory(e.target.value)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      {categories.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Status</label>
                    <select 
                      value={filterCondition} 
                      onChange={(e) => setFilterCondition(e.target.value)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      <option value="All">All Conditions</option>
                      <option value="Good">Good</option>
                      <option value="Fair">Fair</option>
                      <option value="Poor">Poor</option>
                      <option value="Needs Replacement">Warning/Fail</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Sort By</label>
                    <select 
                      value={sortBy} 
                      onChange={(e) => setSortBy(e.target.value as any)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      <option value="name-asc">Name (A-Z)</option>
                      <option value="name-desc">Name (Z-A)</option>
                      <option value="qty-desc">Quantity (High)</option>
                    </select>
                  </div>
                </div>
              )}

              {filteredAndSortedEquipment.length > 0 ? (
                <div className="grid gap-3">
                  {filteredAndSortedEquipment.map((item) => (
                    <div key={item.id} className="bg-white border border-gray-100 rounded-xl p-4 flex justify-between items-center hover:border-red-100 transition-all hover:shadow-sm">
                      <div className="flex-1">
                        <div className="flex items-center space-x-2">
                          <h5 className="font-bold text-gray-900">{item.name}</h5>
                          <span className="text-[10px] font-black bg-gray-100 text-gray-500 px-1.5 py-0.5 rounded uppercase tracking-tighter">
                            {item.category}
                          </span>
                        </div>
                        <p className="text-[10px] text-gray-400 mt-1 flex items-center">
                          <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 00-2 2z" /></svg>
                          Last Check: {item.lastChecked}
                        </p>
                      </div>
                      <div className="text-right ml-4 shrink-0">
                        <div className="text-xs font-black text-gray-900 mb-1">x{item.quantity}</div>
                        <span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter ${getConditionClass(item.condition)}`}>
                          {item.condition}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-16 px-6 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                  <div className="bg-gray-200 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3">
                    <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                  </div>
                  <h5 className="font-bold text-gray-600">No Items Found</h5>
                  <p className="text-xs text-gray-400 mt-1">Try adjusting your filters or add new gear.</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-gray-50 p-4 rounded-xl border border-transparent hover:border-gray-100 transition-colors">
    <span className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-base font-bold text-gray-900">{value}</span>
  </div>
);

const getConditionClass = (condition: Equipment['condition']) => {
  switch (condition) {
    case 'Good': return 'bg-green-100 text-green-700';
    case 'Fair': return 'bg-yellow-100 text-yellow-700';
    case 'Poor': return 'bg-orange-100 text-orange-700';
    case 'Needs Replacement': return 'bg-red-100 text-red-700';
    default: return 'bg-gray-100 text-gray-700';
  }
};

export default VehicleDetails;

import React, { useState, useEffect } from 'react';
import { Vehicle, VehicleStatus, Equipment } from './types';
import { INITIAL_VEHICLES } from './constants';
import Dashboard from './components/Dashboard';
import VehicleCard from './components/VehicleCard';
import VehicleDetails from './components/VehicleDetails';
import { analyzeFleetStatus } from './services/geminiService';

const App: React.FC = () => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(INITIAL_VEHICLES);
  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredVehicles = vehicles.filter(v => 
    v.callSign.toLowerCase().includes(searchTerm.toLowerCase()) || 
    v.type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleUpdateStatus = (id: string, newStatus: VehicleStatus) => {
    setVehicles(prev => prev.map(v => v.id === id ? { ...v, status: newStatus } : v));
    if (selectedVehicle?.id === id) {
      setSelectedVehicle(prev => prev ? { ...prev, status: newStatus } : null);
    }
  };

  const handleAddEquipment = (vehicleId: string, equipment: Equipment) => {
    setVehicles(prev => prev.map(v => 
      v.id === vehicleId 
        ? { ...v, equipment: [...v.equipment, equipment] } 
        : v
    ));
    if (selectedVehicle?.id === vehicleId) {
      setSelectedVehicle(prev => prev ? { ...prev, equipment: [...prev.equipment, equipment] } : null);
    }
  };

  const handleUpdateEquipment = (vehicleId: string, equipmentId: string, updates: Partial<Equipment>) => {
    setVehicles(prev => prev.map(v => 
      v.id === vehicleId 
        ? { 
            ...v, 
            equipment: v.equipment.map(e => e.id === equipmentId ? { ...e, ...updates } : e) 
          } 
        : v
    ));
    if (selectedVehicle?.id === vehicleId) {
      setSelectedVehicle(prev => prev ? { 
        ...prev, 
        equipment: prev.equipment.map(e => e.id === equipmentId ? { ...e, ...updates } : e) 
      } : null);
    }
  };

  const triggerFleetAnalysis = async () => {
    setIsAnalyzing(true);
    setAiAnalysis(null);
    try {
      const result = await analyzeFleetStatus(vehicles);
      setAiAnalysis(result);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-8">
