import React, { useState, useMemo } from 'react';
import { Vehicle, VehicleStatus, Equipment } from '../types';

interface VehicleDetailsProps {
  vehicle: Vehicle;
  onClose: () => void;
  onUpdateStatus: (id: string, status: VehicleStatus) => void;
  onAddEquipment: (vehicleId: string, equipment: Equipment) => void;
  onUpdateEquipment: (vehicleId: string, equipmentId: string, updates: Partial<Equipment>) => void;
}

const VehicleDetails: React.FC<VehicleDetailsProps> = ({ vehicle, onClose, onUpdateStatus, onAddEquipment, onUpdateEquipment }) => {
  const [activeTab, setActiveTab] = useState<'info' | 'inventory'>('info');
  const [isAdding, setIsAdding] = useState(false);

  const today = new Date().toISOString().split('T')[0];

  const [newEq, setNewEq] = useState({
    name: '',
    category: '',
    quantity: 1,
    condition: 'Good' as Equipment['condition'],
    lastChecked: today
  });

  // Filtering and Sorting state
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [filterCondition, setFilterCondition] = useState<string>('All');
  const [sortBy, setSortBy] = useState<'name-asc' | 'name-desc' | 'qty-desc'>('name-asc');

  const categories = useMemo(() => {
    const cats = new Set(vehicle.equipment.map(e => e.category));
    return ['All', ...Array.from(cats)].sort();
  }, [vehicle.equipment]);

  const filteredAndSortedEquipment = useMemo(() => {
    let result = [...vehicle.equipment];

    // Filter by category
    if (filterCategory !== 'All') {
      result = result.filter(e => e.category === filterCategory);
    }

    // Filter by condition
    if (filterCondition !== 'All') {
      result = result.filter(e => e.condition === filterCondition);
    }

    // Sort
    result.sort((a, b) => {
      if (sortBy === 'name-asc') return a.name.localeCompare(b.name);
      if (sortBy === 'name-desc') return b.name.localeCompare(a.name);
      if (sortBy === 'qty-desc') return b.quantity - a.quantity;
      return 0;
    });

    return result;
  }, [vehicle.equipment, filterCategory, filterCondition, sortBy]);

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEq.name || !newEq.category) return;

    const equipment: Equipment = {
      id: Math.random().toString(36).substr(2, 9),
      name: newEq.name,
      category: newEq.category,
      quantity: newEq.quantity,
      condition: newEq.condition,
      lastChecked: newEq.lastChecked || today
    };

    onAddEquipment(vehicle.id, equipment);
    setIsAdding(false);
    setNewEq({ name: '', category: '', quantity: 1, condition: 'Good', lastChecked: today });
  };

  const handleRefreshCheck = (eqId: string) => {
    onUpdateEquipment(vehicle.id, eqId, { lastChecked: today });
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full max-w-2xl h-[90vh] sm:h-auto sm:rounded-2xl overflow-hidden flex flex-col animate-slide-up">
        <div className="fire-gradient p-6 text-white flex justify-between items-center shrink-0 shadow-md">
          <div>
            <h2 className="text-2xl font-bold">{vehicle.callSign}</h2>
            <p className="opacity-80 text-sm font-medium tracking-wide uppercase">{vehicle.type}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex border-b shrink-0 bg-gray-50">
          <button 
            onClick={() => setActiveTab('info')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider transition-all ${activeTab === 'info' ? 'text-red-600 border-b-2 border-red-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            Vehicle Info
          </button>
          <button 
            onClick={() => setActiveTab('inventory')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider transition-all ${activeTab === 'inventory' ? 'text-red-600 border-b-2 border-red-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            Inventory ({vehicle.equipment.length})
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-white">
          {activeTab === 'info' ? (
            <div className="space-y-8 animate-fade-in">
              <section>
                <div className="flex items-center space-x-2 mb-4">
                  <div className="h-1 w-8 bg-red-600 rounded-full" />
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Operational Status</h4>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  {Object.values(VehicleStatus).map(status => (
                    <button
                      key={status}
                      onClick={() => onUpdateStatus(vehicle.id, status)}
                      className={`py-3 px-4 rounded-xl text-sm font-bold border-2 transition-all ${vehicle.status === status ? 'bg-red-50 border-red-500 text-red-700 shadow-sm' : 'bg-white border-gray-100 text-gray-500 hover:border-gray-200'}`}
                    >
                      {status}
                    </button>
                  ))}
                </div>
              </section>

              <section className="grid grid-cols-2 gap-4">
                <InfoBox label="Current Mileage" value={`${vehicle.mileage.toLocaleString()} mi`} />
                <InfoBox label="Last Service" value={vehicle.lastService} />
                <InfoBox label="Deployment Location" value={vehicle.location} />
                <InfoBox label="Crew Capacity" value={`${vehicle.crewCapacity} Persons`} />
              </section>
            </div>
          ) : (
            <div className="space-y-4 animate-fade-in">
              <div className="flex justify-between items-center mb-2">
                <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Equipment Checklist</h4>
                <button 
                  onClick={() => setIsAdding(!isAdding)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center space-x-1 ${isAdding ? 'bg-gray-100 text-gray-600' : 'bg-red-600 text-white shadow-sm hover:bg-red-700'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isAdding ? "M6 18L18 6M6 6l12 12" : "M12 4v16m8-8H4"} /></svg>
                  <span>{isAdding ? 'Cancel' : 'Add Item'}</span>
                </button>
              </div>

              {isAdding && (
                <form onSubmit={handleAddSubmit} className="bg-gray-50 p-4 rounded-xl border border-gray-200 space-y-3 mb-6 animate-slide-up">
                  <div className="grid grid-cols-2 gap-3">
                    <input 
                      type="text" placeholder="Item Name" required
                      className="col-span-2 text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none"
                      value={newEq.name} onChange={e => setNewEq({...newEq, name: e.target.value})}
                    />
                    <input 
                      type="text" placeholder="Category (e.g. Hose, PPE)" required
                      className="text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none"
                      value={newEq.category} onChange={e => setNewEq({...newEq, category: e.target.value})}
                    />
                    <input 
                      type="number" placeholder="Qty" required min="1"
                      className="text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none"
                      value={newEq.quantity} onChange={e => setNewEq({...newEq, quantity: parseInt(e.target.value) || 1})}
                    />
                    <select 
                      className="col-span-1 text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none"
                      value={newEq.condition} onChange={e => setNewEq({...newEq, condition: e.target.value as any})}
                    >
                      <option value="Good">Condition: Good</option>
                      <option value="Fair">Condition: Fair</option>
                      <option value="Poor">Condition: Poor</option>
                      <option value="Needs Replacement">Needs Replacement</option>
                    </select>
                    <div className="col-span-1">
                      <input 
                        type="date" 
                        required
                        className="w-full text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none"
                        value={newEq.lastChecked}
                        onChange={e => setNewEq({...newEq, lastChecked: e.target.value})}
                      />
                    </div>
                  </div>
                  <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-lg font-bold text-sm shadow-md hover:bg-red-700 transition-colors">
                    Register Equipment
                  </button>
                </form>
              )}

              {/* Filtering and Sorting Controls */}
              {!isAdding && vehicle.equipment.length > 0 && (
                <div className="grid grid-cols-3 gap-2 p-3 bg-gray-50 rounded-xl border border-gray-100">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Category</label>
                    <select 
                      value={filterCategory} 
                      onChange={(e) => setFilterCategory(e.target.value)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      {categories.map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Status</label>
                    <select 
                      value={filterCondition} 
                      onChange={(e) => setFilterCondition(e.target.value)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      <option value="All">All Conditions</option>
                      <option value="Good">Good</option>
                      <option value="Fair">Fair</option>
                      <option value="Poor">Poor</option>
                      <option value="Needs Replacement">Warning/Fail</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase">Sort By</label>
                    <select 
                      value={sortBy} 
                      onChange={(e) => setSortBy(e.target.value as any)}
                      className="w-full text-[11px] font-bold p-1 bg-white rounded border border-gray-200 outline-none"
                    >
                      <option value="name-asc">Name (A-Z)</option>
                      <option value="name-desc">Name (Z-A)</option>
                      <option value="qty-desc">Quantity (High)</option>
                    </select>
                  </div>
                </div>
              )}

              {filteredAndSortedEquipment.length > 0 ? (
                <div className="grid gap-3">
                  {filteredAndSortedEquipment.map((item) => (
                    <div key={item.id} className="bg-white border border-gray-100 rounded-xl p-4 flex justify-between items-center hover:border-red-100 transition-all hover:shadow-sm">
                      <div className="flex-1">
                        <div className="flex items-center space-x-2">
                          <h5 className="font-bold text-gray-900">{item.name}</h5>
                          <span className="text-[10px] font-black bg-gray-100 text-gray-500 px-1.5 py-0.5 rounded uppercase tracking-tighter">
                            {item.category}
                          </span>
                        </div>
                        <div className="flex items-center space-x-3 mt-1">
                          <p className="text-[10px] text-gray-400 flex items-center">
                            <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 00-2 2z" /></svg>
                            Check: <span className="font-bold ml-1 text-gray-500">{item.lastChecked}</span>
                          </p>
                          <button 
                            onClick={() => handleRefreshCheck(item.id)}
                            className="text-[9px] font-black text-red-600 hover:text-red-700 uppercase tracking-tighter border border-red-100 px-1.5 py-0.5 rounded hover:bg-red-50 transition-colors"
                          >
                            Mark Checked Today
                          </button>
                        </div>
                      </div>
                      <div className="text-right ml-4 shrink-0">
                        <div className="text-xs font-black text-gray-900 mb-1">x{item.quantity}</div>
                        <span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-tighter ${getConditionClass(item.condition)}`}>
                          {item.condition}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-16 px-6 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                  <div className="bg-gray-200 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3">
                    <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                  </div>
                  <h5 className="font-bold text-gray-600">No Items Found</h5>
                  <p className="text-xs text-gray-400 mt-1">Try adjusting your filters or add new gear.</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
