import React, { useState, useEffect } from 'react';
import { Vehicle, VehicleStatus, Equipment, HistoryEntry } from './types';
import { INITIAL_VEHICLES } from './constants';
import Dashboard from './components/Dashboard';
import VehicleCard from './components/VehicleCard';
import VehicleDetails from './components/VehicleDetails';
import { analyzeFleetStatus } from './services/geminiService';

const App: React.FC = () => {
  const [vehicles, setVehicles] = useState<Vehicle[]>(INITIAL_VEHICLES);
  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredVehicles = vehicles.filter(v => 
    v.callSign.toLowerCase().includes(searchTerm.toLowerCase()) || 
    v.type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleUpdateStatus = (id: string, newStatus: VehicleStatus) => {
    const today = new Date().toISOString().split('T')[0];
    const historyEntry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      date: today,
      type: 'status',
      description: `Status updated to ${newStatus}.`
    };

    setVehicles(prev => prev.map(v => 
      v.id === id 
        ? { ...v, status: newStatus, history: [historyEntry, ...v.history] } 
        : v
    ));
    if (selectedVehicle?.id === id) {
      setSelectedVehicle(prev => prev ? { ...prev, status: newStatus, history: [historyEntry, ...prev.history] } : null);
    }
  };

  const handleAddEquipment = (vehicleId: string, equipment: Equipment) => {
    const today = new Date().toISOString().split('T')[0];
    const historyEntry: HistoryEntry = {
      id: Math.random().toString(36).substr(2, 9),
      date: today,
      type: 'equipment',
      description: `Added new equipment: ${equipment.name} (${equipment.quantity} units).`
    };

    setVehicles(prev => prev.map(v => 
      v.id === vehicleId 
        ? { ...v, equipment: [...v.equipment, equipment], history: [historyEntry, ...v.history] } 
        : v
    ));
    if (selectedVehicle?.id === vehicleId) {
      setSelectedVehicle(prev => prev ? { ...prev, equipment: [...prev.equipment, equipment], history: [historyEntry, ...prev.history] } : null);
    }
  };

  const handleUpdateEquipment = (vehicleId: string, equipmentId: string, updates: Partial<Equipment>) => {
    const eqName = selectedVehicle?.equipment.find(e => e.id === equipmentId)?.name || 'Equipment';
    const today = new Date().toISOString().split('T')[0];

    // Only log if lastChecked is the only update (manual check)
    let historyEntry: HistoryEntry | null = null;
    if (updates.lastChecked && Object.keys(updates).length === 1) {
      historyEntry = {
        id: Math.random().toString(36).substr(2, 9),
        date: today,
        type: 'equipment',
        description: `Verified condition of ${eqName}.`
      };
    }

    setVehicles(prev => prev.map(v => 
      v.id === vehicleId 
        ? { 
            ...v, 
            equipment: v.equipment.map(e => e.id === equipmentId ? { ...e, ...updates } : e),
            history: historyEntry ? [historyEntry, ...v.history] : v.history
          } 
        : v
    ));
    if (selectedVehicle?.id === vehicleId) {
      setSelectedVehicle(prev => prev ? { 
        ...prev, 
        equipment: prev.equipment.map(e => e.id === equipmentId ? { ...e, ...updates } : e),
        history: historyEntry ? [historyEntry, ...prev.history] : prev.history
      } : null);
    }
  };

  const handleAddHistoryEntry = (vehicleId: string, entry: Omit<HistoryEntry, 'id'>) => {
    const fullEntry: HistoryEntry = {
      ...entry,
      id: Math.random().toString(36).substr(2, 9)
    };
    setVehicles(prev => prev.map(v => 
      v.id === vehicleId ? { ...v, history: [fullEntry, ...v.history] } : v
    ));
    if (selectedVehicle?.id === vehicleId) {
      setSelectedVehicle(prev => prev ? { ...prev, history: [fullEntry, ...prev.history] } : null);
    }
  };

  const triggerFleetAnalysis = async () => {
    setIsAnalyzing(true);
    setAiAnalysis(null);
    try {
      const result = await analyzeFleetStatus(vehicles);
      setAiAnalysis(result);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-8">
      {/* Header */}
      <header className="fire-gradient text-white pt-8 pb-12 px-6 sticky top-0 z-40 shadow-lg">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-black tracking-tighter uppercase">FireTrack Pro</h1>
            <p className="text-xs opacity-75 font-medium tracking-widest uppercase mt-1">Central Fleet Command</p>
          </div>
          <button 
            onClick={triggerFleetAnalysis}
            disabled={isAnalyzing}
            className="bg-white/20 hover:bg-white/30 backdrop-blur-md px-4 py-2 rounded-lg text-sm font-bold flex items-center space-x-2 transition-all active:scale-95 disabled:opacity-50"
          >
            {isAnalyzing ? (
              <div className="animate-spin h-4 w-4 border-2 border-white/50 border-t-white rounded-full" />
            ) : (
              <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M13 6a3 3 0 11-6 0 3 3 0 016 0zM18 8a2 2 0 11-4 0 2 2 0 014 0zM14 15a4 4 0 00-8 0v3h8v-3zM6 8a2 2 0 11-4 0 2 2 0 014 0zM16 18v-3a5.972 5.972 0 00-.75-2.906A3.005 3.005 0 0119 15v3h-3zM4.75 12.094A5.973 5.973 0 004 15v3H1v-3a3.005 3.005 0 013.75-2.906z" /></svg>
            )}
            <span>AI Fleet Audit</span>
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto -mt-8 px-4 sm:px-6 relative z-10">
        <Dashboard vehicles={vehicles} />

        {aiAnalysis && (
          <div className="mb-8 bg-blue-50 border border-blue-100 rounded-2xl p-6 relative overflow-hidden animate-fade-in">
            <div className="absolute top-0 right-0 p-4 opacity-5">
              <svg className="w-24 h-24 text-blue-900" fill="currentColor" viewBox="0 0 20 20"><path d="M10 12a2 2 0 100-4 2 2 0 000 4z" /><path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z" clipRule="evenodd" /></svg>
            </div>
            <div className="flex items-center space-x-2 mb-3">
              <div className="h-2 w-2 rounded-full bg-blue-500 animate-pulse" />
              <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wide">AI Deployment Advisor</h3>
            </div>
            <div className="text-blue-900 text-sm leading-relaxed whitespace-pre-wrap">
              {aiAnalysis}
            </div>
            <button 
              onClick={() => setAiAnalysis(null)}
              className="mt-4 text-xs font-bold text-blue-700 hover:underline"
            >
              Dismiss Analysis
            </button>
          </div>
        )}

        <div className="mb-6 flex flex-col sm:flex-row gap-4">
          <div className="relative flex-1">
            <input 
              type="text" 
              placeholder="Search call sign or type..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-white rounded-xl py-3 pl-11 pr-4 border border-gray-200 focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent transition-all shadow-sm"
            />
            <svg className="w-5 h-5 text-gray-400 absolute left-4 top-1/2 -translate-y-1/2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 gap-4">
          {filteredVehicles.map(vehicle => (
            <VehicleCard 
              key={vehicle.id} 
              vehicle={vehicle} 
              onSelect={setSelectedVehicle} 
            />
          ))}
          {filteredVehicles.length === 0 && (
            <div className="col-span-full py-12 text-center text-gray-400 bg-white rounded-2xl border-2 border-dashed border-gray-100">
              No vehicles matching your search.
            </div>
          )}
        </div>
      </main>

      {selectedVehicle && (
        <VehicleDetails 
          vehicle={selectedVehicle} 
          onClose={() => setSelectedVehicle(null)} 
          onUpdateStatus={handleUpdateStatus}
          onAddEquipment={handleAddEquipment}
          onUpdateEquipment={handleUpdateEquipment}
          onAddHistoryEntry={handleAddHistoryEntry}
        />
      )}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 flex justify-around items-center p-3 md:hidden z-30 shadow-2xl">
        <NavItem active label="Fleet" icon={<svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" /></svg>} />
        <NavItem label="Dispatch" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>} />
        <NavItem label="Alerts" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>} />
        <NavItem label="Admin" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>} />
      </nav>
    </div>
  );
};

const NavItem: React.FC<{ icon: React.ReactNode; label: string; active?: boolean }> = ({ icon, label, active }) => (
  <button className={`flex flex-col items-center space-y-1 ${active ? 'text-red-600' : 'text-gray-400'}`}>
    {icon}
