           <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Fleet Preview</h3>
           <span className="text-[10px] font-bold text-red-600 bg-red-50 px-2 py-0.5 rounded-full">LIVE VIEW</span>
        </div>
        <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
          {vehicles.map(v => (
            <div key={v.id} className="flex-shrink-0 group">
