                               <span className="text-[9px] font-mono bg-gray-100 text-gray-500 px-1 rounded">
                                 #<Highlight text={item.id} search={equipmentSearch} />
                               </span>
                               <h5 className="font-bold text-gray-900 leading-tight">
                                 <Highlight text={item.name} search={equipmentSearch} />
                               </h5>
