                    </div>
                    <div className="bg-gray-50/50 px-4 py-2 flex justify-end border-t border-gray-50">
                      <button 
                        onClick={() => handleRefreshCheck(item.id)} 
                        className="text-[9px] font-black text-red-600 hover:text-red-700 uppercase tracking-tighter border border-red-200 px-3 py-1 rounded-lg hover:bg-white transition-colors flex items-center bg-white/50 shadow-sm"
                      >
                        <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg>
                        Verify Check-off
                      </button>
                    </div>
                  </div>
                ))}
                {filteredAndSortedEquipment.length === 0 && (
                  <div className="text-center py-12 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                    <p className="text-sm text-gray-400 font-medium">No equipment matches your search criteria.</p>
                    <button 
                      onClick={() => setEquipmentSearch("")} 
                      className="mt-2 text-xs font-bold text-red-600 hover:underline"
                    >
                      Clear Search
                    </button>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-6 animate-fade-in">
              <div className="flex justify-between items-center">
                <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Service & Event Log</h4>
                <button 
                  onClick={() => setIsAddingLog(!isAddingLog)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center space-x-1 ${isAddingLog ? 'bg-gray-100 text-gray-600' : 'bg-red-600 text-white'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isAddingLog ? "M6 18L18 6M6 6l12 12" : "M12 4v16m8-8H4"} /></svg>
                  <span>Log Event</span>
                </button>
              </div>

              {isAddingLog && (
                <form onSubmit={handleAddLogSubmit} className="bg-gray-50 p-4 rounded-xl border border-gray-200 space-y-3 mb-6 animate-slide-up">
                  <div className="grid grid-cols-2 gap-3">
                    <select className="text-sm p-2 rounded-lg border outline-none" value={newLog.type} onChange={e => setNewLog({...newLog, type: e.target.value as any})}>
                      <option value="note">General Note</option>
                      <option value="maintenance">Maintenance Entry</option>
                      <option value="status">Status Event</option>
                    </select>
                    <input type="date" required className="text-sm p-2 rounded-lg border outline-none" value={newLog.date} onChange={e => setNewLog({...newLog, date: e.target.value})} />
                    <textarea 
                      placeholder="Event description..." required 
                      className="col-span-2 text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none h-20"
                      value={newLog.description} onChange={e => setNewLog({...newLog, description: e.target.value})}
                    />
                  </div>
                  <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-lg font-bold text-sm shadow-md hover:bg-red-700">Add to Log</button>
                </form>
              )}

              <div className="relative">
                <div className="absolute left-4 top-0 bottom-0 w-0.5 bg-gray-100 ml-px" />
                <div className="space-y-8 relative">
                  {vehicle.history.map((entry) => (
                    <div key={entry.id} className="flex space-x-4">
                      <div className="relative z-10 shrink-0">
                        {getHistoryIcon(entry.type)}
                      </div>
                      <div className="flex-1 pt-0.5">
                        <div className="flex justify-between items-start mb-1">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{entry.date}</span>
                          <span className={`text-[9px] font-black px-1.5 py-0.5 rounded uppercase ${
                            entry.type === 'maintenance' ? 'bg-orange-50 text-orange-600' : 
                            entry.type === 'status' ? 'bg-blue-50 text-blue-600' : 'bg-gray-50 text-gray-500'
                          }`}>
                            {entry.type}
                          </span>
                        </div>
                        <p className="text-sm text-gray-800 leading-relaxed font-medium">
                          {entry.description}
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const TabButton: React.FC<{ active: boolean; onClick: () => void; label: string }> = ({ active, onClick, label }) => (
  <button 
    onClick={onClick}
    className={`flex-1 min-w-[100px] py-4 text-xs font-bold uppercase tracking-wider transition-all whitespace-nowrap px-4 ${active ? 'text-red-600 border-b-2 border-red-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
  >
    {label}
  </button>
);

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-gray-50 p-4 rounded-xl border border-transparent hover:border-gray-100 transition-colors">
    <span className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-base font-bold text-gray-900">{value}</span>
  </div>
);

const getConditionClass = (condition: Equipment['condition']) => {
  switch (condition) {
    case 'Good': return 'bg-green-100 text-green-700';
    case 'Fair': return 'bg-yellow-100 text-yellow-700';
    case 'Poor': return 'bg-orange-100 text-orange-700';
    case 'Needs Replacement': return 'bg-red-100 text-red-700';
    default: return 'bg-gray-100 text-gray-700';
  }
};

export default VehicleDetails;

export enum VehicleStatus {
  AVAILABLE = 'Available',
  OUT_ON_CALL = 'Out on Call',
  MAINTENANCE = 'Maintenance',
  OUT_OF_SERVICE = 'Out of Service'
}

export enum VehicleType {
  ENGINE = 'Engine (Pumper)',
  LADDER = 'Ladder Truck',
  TANKER = 'Tanker',
  RESCUE = 'Rescue Unit',
  COMMAND = 'Command Vehicle'
}

export interface EquipmentDocument {
  id: string;
  name: string;
  url: string;
  type: 'pdf' | 'doc' | 'link';
}

export interface Equipment {
