  const [isPlayingVideo, setIsPlayingVideo] = useState(false);

  // Link states for Technical Specs
  const [isAddingDocLink, setIsAddingDocLink] = useState(false);
  const [isAddingVideoLink, setIsAddingVideoLink] = useState(false);
  const [newLinkData, setNewLinkData] = useState({ name: '', url: '' });

  const vehicleFileInputRef = useRef<HTMLInputElement>(null);
  const equipmentFileInputRef = useRef<HTMLInputElement>(null);
  const docUploadRef = useRef<HTMLInputElement>(null);
  const videoUploadRef = useRef<HTMLInputElement>(null);

  const [editingEqIdForImage, setEditingEqIdForImage] = useState<string | null>(null);

  const today = new Date().toISOString().split('T')[0];

  const [newEq, setNewEq] = useState({
    name: '',
    category: '',
    quantity: 1,
    condition: 'Good' as Equipment['condition'],
    lastChecked: today,
    notes: '',
    thumbnailUrl: ''
  });

  const [newLog, setNewLog] = useState<{
    type: HistoryEntry['type'];
    description: string;
    date: string;
    equipmentId?: string;
  }>({
    type: 'note',
    description: '',
    date: today,
    equipmentId: ''
  });

  const existingCategories = useMemo(() => {
    const cats = new Set(vehicle.equipment.map(e => e.category));
    return Array.from(cats).sort();
  }, [vehicle.equipment]);

  const filteredAndSortedEquipment = useMemo(() => {
    let items = [...vehicle.equipment];
    if (equipmentSearch.trim()) {
      const query = equipmentSearch.toLowerCase();
      items = items.filter(item => 
        item.name.toLowerCase().includes(query) || 
        item.category.toLowerCase().includes(query) ||
        item.id.toLowerCase().includes(query)
      );
    }
    return items.sort((a, b) => a.name.localeCompare(b.name));
  }, [vehicle.equipment, equipmentSearch]);

  const selectedDetailedEq = useMemo(() => 
    vehicle.equipment.find(e => e.id === detailedEqId),
    [vehicle.equipment, detailedEqId]
  );

  const getYouTubeId = (url: string) => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEq.name || !newEq.category) return;
    const equipment: Equipment = {
      id: Math.random().toString(36).substr(2, 9),
      name: newEq.name,
      category: newEq.category,
      quantity: newEq.quantity,
      condition: newEq.condition,
      lastChecked: newEq.lastChecked || today,
      notes: newEq.notes,
      thumbnailUrl: newEq.thumbnailUrl,
      documents: []
    };
    onAddEquipment(vehicle.id, equipment);
    setIsAdding(false);
    setNewEq({ name: '', category: '', quantity: 1, condition: 'Good', lastChecked: today, notes: '', thumbnailUrl: '' });
  };

  const handleAddLogSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLog.description) return;

    onAddHistoryEntry(vehicle.id, {
      date: newLog.date,
      type: newLog.type,
      description: newLog.description,
      equipmentId: newLog.type === 'equipment' ? newLog.equipmentId : undefined
    });

    setIsAddingLog(false);
    setNewLog({ type: 'note', description: '', date: today, equipmentId: '' });
  };

  const handleRefreshCheck = (eqId: string) => {
    onUpdateEquipment(vehicle.id, eqId, { lastChecked: today });
  };

  const startEditingNote = (item: Equipment) => {
    setEditingNoteId(item.id);
    setTempNote(item.notes || "");
  };

  const saveNote = (eqId: string) => {
    onUpdateEquipment(vehicle.id, eqId, { notes: tempNote });
    setEditingNoteId(null);
  };

  const handleVehicleImageClick = () => {
    vehicleFileInputRef.current?.click();
  };

  const handleVehicleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateVehicleImage(vehicle.id, reader.result as string);
        onAddHistoryEntry(vehicle.id, {
          date: today,
          type: 'note',
          description: "Vehicle profile image updated."
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEquipmentThumbnailClick = (eqId?: string) => {
    setEditingEqIdForImage(eqId || null);
    equipmentFileInputRef.current?.click();
  };

  const handleEquipmentFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (editingEqIdForImage) {
          onUpdateEquipment(vehicle.id, editingEqIdForImage, { thumbnailUrl: base64 });
        } else {
          setNewEq(prev => ({ ...prev, thumbnailUrl: base64 }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddDoc = (url: string, name: string = 'Manual Document') => {
    if (!selectedDetailedEq || !url) return;
    const newDoc: EquipmentDocument = {
      id: Math.random().toString(36).substr(2, 9),
      name: name || "Unnamed Resource",
      url,
      type: url.toLowerCase().includes('.pdf') || url.startsWith('data:application/pdf') ? 'pdf' : 'link'
    };
    onUpdateEquipment(vehicle.id, selectedDetailedEq.id, {
      documents: [...(selectedDetailedEq.documents || []), newDoc]
    });
  };

  const handleRemoveDoc = (docId: string) => {
    if (!selectedDetailedEq) return;
    onUpdateEquipment(vehicle.id, selectedDetailedEq.id, {
      documents: (selectedDetailedEq.documents || []).filter(d => d.id !== docId)
    });
  };

  const handleUploadDoc = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        handleAddDoc(reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUploadVideo = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && selectedDetailedEq) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateEquipment(vehicle.id, selectedDetailedEq.id, { videoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const submitDocLink = (e: React.FormEvent) => {
    e.preventDefault();
    if (newLinkData.url) {
      handleAddDoc(newLinkData.url, newLinkData.name || "Web Manual");
      setNewLinkData({ name: '', url: '' });
      setIsAddingDocLink(false);
    }
  };

  const submitVideoLink = (e: React.FormEvent) => {
    e.preventDefault();
    if (newLinkData.url && selectedDetailedEq) {
      onUpdateEquipment(vehicle.id, selectedDetailedEq.id, { videoUrl: newLinkData.url });
      setNewLinkData({ name: '', url: '' });
      setIsAddingVideoLink(false);
    }
  };

  const getHistoryIcon = (type: HistoryEntry['type']) => {
    switch(type) {
      case 'status': return <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a8 8 0 100 16 8 8 0 000-16zm1 11H9v-2h2v2zm0-4H9V5h2v4z"/></svg></div>;
      case 'maintenance': return <div className="w-8 h-8 rounded-full bg-orange-100 flex items-center justify-center text-orange-600"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M5 4a1 1 0 00-2 0v7.268a2 2 0 000 3.464V16a1 1 0 102 0v-1.268a2 2 0 000-3.464V4zM11 4a1 1 0 10-2 0v1.268a2 2 0 000 3.464V16a1 1 0 102 0V8.732a2 2 0 000-3.464V4zM16 3a1 1 0 011 1v7.268a2 2 0 010 3.464V16a1 1 0 11-2 0v-1.268a2 2 0 010-3.464V4a1 1 0 011-1z"/></svg></div>;
      case 'equipment': return <div className="w-8 h-8 rounded-full bg-green-100 flex items-center justify-center text-green-600"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 2a1 1 0 011 1v1h3a1 1 0 110 2h-3v3h3a1 1 0 110 2h-3v3h3a1 1 0 110 2h-3v1a1 1 0 11-2 0v-1H5a1 1 0 110-2h3v-3H5a1 1 0 110-2h3V6H5a1 1 0 110-2h3V3a1 1 0 011-1z"/></svg></div>;
      default: return <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-600"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M17.414 2.586a2 2 0 00-2.828 0L7 10.172V13h2.828l7.586-7.586a2 2 0 000-2.828zM4 16v4h4v-4H4z"/></svg></div>;
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full max-w-2xl h-[90vh] sm:h-auto sm:rounded-2xl overflow-hidden flex flex-col animate-slide-up relative">

        {/* Equipment Technical Detail Modal Overlay */}
        {selectedDetailedEq && (
          <div className="absolute inset-0 z-[60] bg-white flex flex-col animate-slide-up overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-white sticky top-0 z-10 shadow-sm">
              <div className="flex items-center space-x-3">
                <div className="w-12 h-12 rounded-xl overflow-hidden bg-slate-100 flex-shrink-0 border border-slate-200">
                  {selectedDetailedEq.thumbnailUrl ? (
                    <img src={selectedDetailedEq.thumbnailUrl} className="w-full h-full object-cover" alt="" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-slate-300">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                    </div>
                  )}
                </div>
                <div>
                  <h3 className="font-black text-gray-900 leading-tight uppercase tracking-tight">{selectedDetailedEq.name}</h3>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Technical Specifications</p>
                </div>
              </div>
              <button onClick={() => { setDetailedEqId(null); setIsPlayingVideo(false); }} className="p-2 hover:bg-gray-100 rounded-full transition-colors group">
                <svg className="w-6 h-6 text-gray-400 group-hover:text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-12">
              {/* Manuals & Documents Section */}
              <section>
                <div className="flex justify-between items-center mb-6">
                  <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">Manuals & Documents</h4>
                  <div className="flex items-center space-x-2">
                    {!isAddingDocLink && (
                      <>
                        <button 
                          onClick={() => docUploadRef.current?.click()} 
                          className="text-[10px] font-black text-red-600 bg-red-50/50 border border-red-100 px-3 py-1.5 rounded-lg hover:bg-red-50 transition-all active:scale-95 shadow-sm"
                        >
                          Upload PDF
                        </button>
                        <input type="file" ref={docUploadRef} className="hidden" accept=".pdf" onChange={handleUploadDoc} />
                        <button 
                          onClick={() => {
                            setIsAddingDocLink(true);
                            setIsAddingVideoLink(false);
                            setNewLinkData({ name: '', url: '' });
                          }} 
                          className="text-[10px] font-black text-slate-600 bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-100 transition-all active:scale-95 shadow-sm"
                        >
                          Add Link
                        </button>
                      </>
                    )}
                  </div>
                </div>

                {/* Inline form for adding a document link */}
                {isAddingDocLink && (
                  <form onSubmit={submitDocLink} className="mb-6 bg-slate-50 p-4 rounded-2xl border border-slate-200 animate-slide-up space-y-3">
                    <div className="flex justify-between items-center">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Register New Link</span>
                      <button type="button" onClick={() => setIsAddingDocLink(false)} className="text-slate-400 hover:text-slate-600">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                    <div className="grid grid-cols-1 gap-3">
                      <input 
                        type="text" 
                        placeholder="Link Label (e.g. User Manual 2024)" 
                        required 
                        className="text-xs p-2.5 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-red-500"
                        value={newLinkData.name}
                        onChange={e => setNewLinkData({...newLinkData, name: e.target.value})}
                      />
                      <input 
                        type="url" 
                        placeholder="https://manufacturer.com/manual.pdf" 
                        required 
                        className="text-xs p-2.5 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-red-500"
                        value={newLinkData.url}
                        onChange={e => setNewLinkData({...newLinkData, url: e.target.value})}
                      />
                    </div>
                    <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md hover:bg-red-700 transition-colors">
                      Confirm Link
                    </button>
                  </form>
                )}

                <div className="space-y-2.5">
                  {(selectedDetailedEq.documents || []).length > 0 ? (
                    selectedDetailedEq.documents?.map(doc => (
                      <div key={doc.id} className="group relative flex items-center">
                        <a 
                          href={doc.url} 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          className="flex-1 flex items-center p-3.5 rounded-xl border border-slate-100 bg-white hover:border-red-200 hover:bg-red-50/10 transition-all shadow-sm active:scale-[0.99]"
                        >
                          <div className="w-10 h-10 rounded-lg bg-red-50/50 flex items-center justify-center text-red-600 mr-4 border border-red-100/30">
                            {doc.type === 'pdf' ? (
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                            ) : (
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                            )}
                          </div>
                          <span className="flex-1 text-xs font-black text-slate-700 tracking-tight truncate mr-2">{doc.name}</span>
                          <svg className="w-4 h-4 text-slate-300 group-hover:text-red-400 group-hover:translate-x-1 transition-all" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg>
                        </a>
                        <button 
                          onClick={(e) => { e.preventDefault(); handleRemoveDoc(doc.id); }}
                          className="p-3 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                          title="Remove Resource"
                        >
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7" /></svg>
                        </button>
                      </div>
                    ))
                  ) : (
                    <div className="py-14 text-center border-2 border-dashed rounded-3xl border-slate-100 bg-slate-50/30">
                      <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-200 mx-auto mb-3 shadow-sm border border-slate-50">
                         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
                      </div>
                      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.1em]">No documentation links recorded</p>
                    </div>
                  )}
                </div>
              </section>

              {/* Videos & Training Section */}
              <section>
                <div className="flex justify-between items-center mb-6">
                  <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.15em]">Videos & Training</h4>
                  <div className="flex items-center space-x-2">
                    {!isAddingVideoLink && (
                      <>
                        <button 
                          onClick={() => videoUploadRef.current?.click()} 
                          className="text-[10px] font-black text-red-600 bg-red-50/50 border border-red-100 px-3 py-1.5 rounded-lg hover:bg-red-50 transition-all active:scale-95 shadow-sm"
                        >
                          Upload Video
                        </button>
                        <input type="file" ref={videoUploadRef} className="hidden" accept="video/*" onChange={handleUploadVideo} />
                        <button 
                          onClick={() => {
                            setIsAddingVideoLink(true);
                            setIsAddingDocLink(false);
                            setNewLinkData({ name: '', url: '' });
                          }} 
                          className="text-[10px] font-black text-slate-600 bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-100 transition-all active:scale-95 shadow-sm"
                        >
                          Add Link
                        </button>
                      </>
                    )}
                  </div>
                </div>

                {/* Inline form for adding a video link */}
                {isAddingVideoLink && (
                  <form onSubmit={submitVideoLink} className="mb-6 bg-slate-50 p-4 rounded-2xl border border-slate-200 animate-slide-up space-y-3">
                    <div className="flex justify-between items-center">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Training Source URL</span>
                      <button type="button" onClick={() => setIsAddingVideoLink(false)} className="text-slate-400 hover:text-slate-600">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                    </div>
                    <input 
                      type="url" 
                      placeholder="https://youtube.com/watch?v=..." 
                      required 
                      className="w-full text-xs p-2.5 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-red-500"
                      value={newLinkData.url}
                      onChange={e => setNewLinkData({...newLinkData, url: e.target.value})}
                    />
                    <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md hover:bg-red-700 transition-colors">
                      Register Video
                    </button>
                  </form>
                )}

                {selectedDetailedEq.videoUrl ? (
                  <div className="rounded-2xl overflow-hidden border border-slate-100 bg-slate-900 shadow-md relative group ring-1 ring-slate-950/5 max-w-[240px] mx-auto aspect-video">
                    {/* Inline Player */}
                    {isPlayingVideo ? (
                      <div className="w-full h-full relative">
                        {selectedDetailedEq.videoUrl.startsWith('data:video') ? (
                          <video src={selectedDetailedEq.videoUrl} controls autoPlay className="w-full h-full object-contain" />
                        ) : getYouTubeId(selectedDetailedEq.videoUrl) ? (
                          <iframe 
                            src={`https://www.youtube.com/embed/${getYouTubeId(selectedDetailedEq.videoUrl)}?autoplay=1&modestbranding=1&rel=0`}
                            className="w-full h-full border-0 absolute inset-0"
                            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                            allowFullScreen
                          ></iframe>
                        ) : (
                          <div className="w-full h-full flex flex-col items-center justify-center p-4 bg-slate-800 text-center">
                            <p className="text-[9px] font-black text-white/70 uppercase">Format unsupportable</p>
                            <a href={selectedDetailedEq.videoUrl} target="_blank" rel="noopener" className="mt-2 text-[8px] underline text-blue-400">Open External</a>
                          </div>
                        )}
                        <button 
                          onClick={() => setIsPlayingVideo(false)}
                          className="absolute top-1 right-1 bg-black/50 hover:bg-red-600 text-white p-1 rounded z-30 transition-colors"
                          title="Stop playback"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      </div>
                    ) : (
                      <div className="w-full h-full relative overflow-hidden flex flex-col items-center justify-center text-white bg-slate-900 text-center">
                        {getYouTubeId(selectedDetailedEq.videoUrl) ? (
                          <>
                            <img 
                              src={`https://img.youtube.com/vi/${getYouTubeId(selectedDetailedEq.videoUrl)}/mqdefault.jpg`}
                              className="absolute inset-0 w-full h-full object-cover opacity-80 group-hover:scale-105 group-hover:opacity-60 transition-all duration-500"
                              alt="Training Preview"
                              onError={(e) => {
                                (e.target as HTMLImageElement).src = `https://img.youtube.com/vi/${getYouTubeId(selectedDetailedEq.videoUrl!)}/hqdefault.jpg`;
                              }}
                            />
                            <div className="relative z-10 p-2 w-full flex flex-col items-center">
                              <button 
                                onClick={() => setIsPlayingVideo(true)}
                                className="w-10 h-10 rounded-full bg-red-600/95 flex items-center justify-center mb-1 shadow-lg shadow-red-600/20 hover:scale-110 active:scale-95 transition-all duration-300"
                              >
                                <svg className="w-5 h-5 ml-0.5 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M4.516 7.548c0-.423.364-.766.814-.766.45 0 .814.343.814.766v4.904c0 .423-.364.766-.814.766-.45 0-.814-.343-.814-.766V7.548zM14.67 7.548c0-.423.364-.766.814-.766.45 0 .814.343.814.766v4.904c0 .423-.364.766-.814.766-.45 0-.814-.343-.814-.766V7.548z" /><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                              </button>
                              <h5 className="font-black text-[8px] uppercase tracking-[0.2em] bg-black/60 px-2 py-0.5 rounded backdrop-blur-sm">Lecture rapide</h5>
                            </div>
                          </>
                        ) : (
                          <div className="p-4">
                            <button 
                              onClick={() => setIsPlayingVideo(true)}
                              className="w-10 h-10 rounded-full bg-red-600 flex items-center justify-center mb-2 shadow-lg shadow-red-600/20 hover:scale-105 transition-transform duration-300 mx-auto"
                            >
                              <svg className="w-5 h-5 ml-0.5" fill="currentColor" viewBox="0 0 20 20"><path d="M4.516 7.548c0-.423.364-.766.814-.766.45 0 .814.343.814.766v4.904c0 .423-.364.766-.814.766-.45 0-.814-.343-.814-.766V7.548zM14.67 7.548c0-.423.364-.766.814-.766.45 0 .814.343.814.766v4.904c0 .423-.364.766-.814.766-.45 0-.814-.343-.814-.766V7.548z" /><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                            </button>
                            <h5 className="font-black text-[8px] uppercase tracking-tight text-white/70">Voir le guide</h5>
                          </div>
                        )}
                        <button 
                          onClick={() => onUpdateEquipment(vehicle.id, selectedDetailedEq.id, { videoUrl: undefined })}
                          className="absolute top-2 right-2 p-1 bg-black/60 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600 shadow-lg backdrop-blur-md z-20"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7" /></svg>
                        </button>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="py-12 text-center border-2 border-dashed rounded-3xl border-slate-100 bg-slate-50/30 flex flex-col items-center max-w-[240px] mx-auto">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-slate-200 mb-2 shadow-sm border border-slate-50">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    </div>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.1em]">No videos provided</p>
                  </div>
                )}
              </section>
            </div>

            <div className="p-5 bg-white border-t flex justify-center sticky bottom-0 z-10">
              <button 
                onClick={() => { setDetailedEqId(null); setIsPlayingVideo(false); }} 
                className="bg-slate-900 text-white px-16 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-slate-900/30 active:scale-[0.97] transition-all hover:bg-slate-800"
              >
                Back to Checklist
              </button>
            </div>
          </div>
        )}

        {/* Existing Header with Image */}
        <div className="relative h-48 shrink-0 group">
          <img src={vehicle.imageUrl} alt={vehicle.callSign} className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-black/20" />
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
              onClick={handleVehicleImageClick}
              className="bg-white/20 hover:bg-white/40 backdrop-blur-md text-white px-4 py-2 rounded-full font-bold text-sm flex items-center space-x-2 border border-white/30 transition-all"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
              <span>Update Photo</span>
            </button>
            <input type="file" ref={vehicleFileInputRef} className="hidden" accept="image/*" onChange={handleVehicleFileChange} />
          </div>
          <div className="absolute bottom-6 left-6 text-white pointer-events-none">
            <h2 className="text-3xl font-black tracking-tight">{vehicle.callSign}</h2>
            <p className="opacity-80 text-sm font-bold tracking-widest uppercase">{vehicle.type}</p>
          </div>
          <button onClick={onClose} className="absolute top-4 right-4 p-2 bg-black/20 hover:bg-black/40 backdrop-blur-md rounded-full text-white transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <input type="file" ref={equipmentFileInputRef} className="hidden" accept="image/*" onChange={handleEquipmentFileChange} />

        <div className="flex border-b shrink-0 bg-gray-50 overflow-x-auto scrollbar-hide">
          <TabButton active={activeTab === 'info'} onClick={() => setActiveTab('info')} label="Info" />
          <TabButton active={activeTab === 'inventory'} onClick={() => setActiveTab('inventory')} label={`Inventory (${vehicle.equipment.length})`} />
          <TabButton active={activeTab === 'history'} onClick={() => setActiveTab('history')} label="History Log" />
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-white">
          {activeTab === 'info' && (
            <div className="space-y-8 animate-fade-in">
              <section>
                <div className="flex items-center space-x-2 mb-4">
                  <div className="h-1 w-8 bg-red-600 rounded-full" />
                  <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Operational Status</h4>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  {Object.values(VehicleStatus).map(status => (
                    <button
                      key={status}
                      onClick={() => onUpdateStatus(vehicle.id, status)}
                      className={`py-3 px-4 rounded-xl text-sm font-bold border-2 transition-all ${vehicle.status === status ? 'bg-red-50 border-red-500 text-red-700 shadow-sm' : 'bg-white border-gray-100 text-gray-500 hover:border-gray-200'}`}
                    >
                      {status}
                    </button>
                  ))}
                </div>
              </section>
              <section className="grid grid-cols-2 gap-4">
                <InfoBox label="Current Mileage" value={`${vehicle.mileage.toLocaleString()} mi`} />
                <InfoBox label="Last Service" value={vehicle.lastService} />
                <InfoBox label="Deployment Location" value={vehicle.location} />
                <InfoBox label="Crew Capacity" value={`${vehicle.crewCapacity} Persons`} />
              </section>
            </div>
          )}

          {activeTab === 'inventory' && (
            <div className="space-y-4 animate-fade-in">
              <div className="flex justify-between items-center mb-2">
                <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Equipment Checklist</h4>
                <button 
                  onClick={() => setIsAdding(!isAdding)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center space-x-1 ${isAdding ? 'bg-gray-100 text-gray-600' : 'bg-red-600 text-white shadow-sm hover:bg-red-700'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isAdding ? "M6 18L18 6M6 6l12 12" : "M12 4v16m8-8H4"} /></svg>
                  <span>{isAdding ? 'Cancel' : 'Add Item'}</span>
                </button>
              </div>

              {!isAdding && (
                <div className="relative mb-4">
                  <input 
                    type="text" 
                    placeholder="Search by ID, name, or category..."
                    value={equipmentSearch}
                    onChange={(e) => setEquipmentSearch(e.target.value)}
                    className="w-full text-sm py-2.5 pl-10 pr-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-red-500 focus:bg-white transition-all outline-none"
                  />
                  <svg className="w-4 h-4 text-gray-400 absolute left-3.5 top-1/2 -translate-y-1/2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                  {equipmentSearch && (
                    <button onClick={() => setEquipmentSearch("")} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                      <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" /></svg>
                    </button>
                  )}
                </div>
              )}

              {isAdding && (
                <form onSubmit={handleAddSubmit} className="bg-gray-50 p-4 rounded-xl border border-gray-200 space-y-4 mb-6 animate-slide-up">
                  <div className="flex items-center space-x-4">
                    <button 
                      type="button"
                      onClick={() => handleEquipmentThumbnailClick()}
                      className="w-16 h-16 rounded-lg bg-gray-200 border-2 border-dashed border-gray-300 flex flex-col items-center justify-center overflow-hidden shrink-0 hover:border-red-400 transition-colors"
                    >
                      {newEq.thumbnailUrl ? (
                        <img src={newEq.thumbnailUrl} className="w-full h-full object-cover" alt="" />
                      ) : (
                        <div className="flex flex-col items-center">
                          <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 00-2 2z" /></svg>
                          <span className="text-[8px] font-bold text-gray-400 uppercase mt-1">Photo</span>
                        </div>
                      )}
                    </button>
                    <input type="text" placeholder="Item Name" required className="flex-1 text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none" value={newEq.name} onChange={e => setNewEq({...newEq, name: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="relative">
                      <input 
                        list="categories-list"
                        type="text" 
                        placeholder="Equipment Category" 
                        required 
                        className="w-full text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none" 
                        value={newEq.category} 
                        onChange={e => setNewEq({...newEq, category: e.target.value})} 
                      />
                      <datalist id="categories-list">
                        {existingCategories.map(cat => <option key={cat} value={cat} />)}
                        <option value="Hose" />
                        <option value="PPE" />
                        <option value="Tools" />
                        <option value="Medical" />
                        <option value="Forcible Entry" />
                        <option value="Ventilation" />
                        <option value="Lighting" />
                      </datalist>
                    </div>
                    <input type="number" placeholder="Qty" required min="1" className="text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none" value={newEq.quantity} onChange={e => setNewEq({...newEq, quantity: parseInt(e.target.value) || 1})} />
                    <select className="text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none" value={newEq.condition} onChange={e => setNewEq({...newEq, condition: e.target.value as any})}>
                      <option value="Good">Good</option>
                      <option value="Fair">Fair</option>
                      <option value="Poor">Poor</option>
                      <option value="Needs Replacement">Replace</option>
                    </select>
                    <input type="date" required className="text-sm p-2 rounded-lg border focus:ring-2 focus:ring-red-500 outline-none" value={newEq.lastChecked} onChange={e => setNewEq({...newEq, lastChecked: e.target.value})} />
                    <textarea placeholder="Notes (optional)" className="col-span-2 text-sm p-2 rounded-lg border h-16" value={newEq.notes} onChange={e => setNewEq({...newEq, notes: e.target.value})} />
                  </div>
                  <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-lg font-bold text-sm shadow-md transition-all active:scale-95">Register Gear</button>
                </form>
              )}

              <div className="grid gap-4">
                {filteredAndSortedEquipment.map((item) => (
                  <div key={item.id} className="bg-white border border-gray-100 rounded-xl overflow-hidden hover:border-red-200 transition-all hover:shadow-sm">
                    <div className="p-4 flex space-x-4">
                      <button 
                        onClick={() => handleEquipmentThumbnailClick(item.id)}
                        className="w-16 h-16 rounded-lg bg-gray-50 border border-gray-100 flex items-center justify-center overflow-hidden shrink-0 group/item transition-all hover:ring-2 hover:ring-red-500"
                      >
                        {item.thumbnailUrl ? (
                          <img src={item.thumbnailUrl} className="w-full h-full object-cover" alt={item.name} />
                        ) : (
                          <div className="flex flex-col items-center opacity-40">
                            <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                            <span className="text-[8px] font-black uppercase mt-1">Add Photo</span>
                          </div>
                        )}
                      </button>

                      <div className="flex-1">
                        <div className="grid grid-cols-12 gap-2 items-start">
                          <div className="col-span-8">
                            <div className="flex items-center space-x-2">
                               <span className="text-[9px] font-mono bg-gray-100 text-gray-500 px-1 rounded">
                                 #<Highlight text={item.id} search={equipmentSearch} />
                               </span>
                               <h5 className="font-bold text-gray-900 leading-tight">
                                 <Highlight text={item.name} search={equipmentSearch} />
                               </h5>
                            </div>
                            <div className="flex flex-wrap items-center gap-2 mt-2">
                               <span className="text-[10px] font-bold text-gray-500 uppercase bg-gray-50 px-2 py-0.5 rounded border border-gray-100">
                                 <Highlight text={item.category} search={equipmentSearch} />
                               </span>
                               <div className="flex items-center text-[10px] text-gray-400">
                                  <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 00-2 2z" /></svg>
                                  Check: <span className="font-semibold text-gray-600 ml-1">{item.lastChecked}</span>
                               </div>
                            </div>
                          </div>
                          <div className="col-span-4 text-right">
                            <div className="text-xs font-black text-gray-900">Qty: {item.quantity}</div>
                            <div className={`text-[10px] font-black px-2 py-0.5 rounded-full inline-block mt-1 uppercase tracking-tighter ${getConditionClass(item.condition)}`}>
                              {item.condition}
                            </div>
                          </div>
                        </div>

                        <div className="mt-3 pt-3 border-t border-gray-50">
                          <div className="flex justify-between items-center mb-1">
                            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Notes</span>
                            <div className="flex items-center space-x-3">
                              {editingNoteId !== item.id && (
                                <button onClick={() => startEditingNote(item)} className="text-[9px] font-bold text-blue-600 hover:text-blue-700 flex items-center">
                                  <svg className="w-2 h-2 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                                  Edit Note
                                </button>
                              )}
                              <button onClick={() => setDetailedEqId(item.id)} className="text-[9px] font-black text-red-600 hover:text-red-700 uppercase flex items-center bg-red-50 px-2 py-0.5 rounded transition-colors group">
                                <svg className="w-2 h-2 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                Tech Specs
                              </button>
                            </div>
                          </div>
                          {editingNoteId === item.id ? (
                            <div className="space-y-2">
                              <textarea className="w-full text-xs p-2 border rounded focus:ring-1 focus:ring-blue-500 outline-none h-16" value={tempNote} onChange={(e) => setTempNote(e.target.value)} autoFocus />
                              <div className="flex justify-end space-x-2">
                                <button onClick={() => setEditingNoteId(null)} className="text-[10px] font-bold text-gray-400">Cancel</button>
                                <button onClick={() => saveNote(item.id)} className="text-[10px] font-bold text-blue-600">Save</button>
                              </div>
                            </div>
                          ) : (
                            <p className="text-xs text-gray-600 italic">{item.notes || "No additional notes recorded."}</p>
                          )}
                        </div>
                      </div>
                    </div>
                    <div className="bg-gray-50/50 px-4 py-2 flex justify-end border-t border-gray-50">
                      <button 
                        onClick={() => handleRefreshCheck(item.id)} 
                        className="text-[9px] font-black text-red-600 hover:text-red-700 uppercase tracking-tighter border border-red-200 px-3 py-1 rounded-lg hover:bg-white transition-colors flex items-center bg-white/50 shadow-sm"
                      >
                        <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" /></svg>
                        Verify Check-off
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-6 animate-fade-in">
              <div className="flex justify-between items-center">
                <h4 className="text-xs font-black text-gray-500 uppercase tracking-widest">Service & Event Log</h4>
                <button 
                  onClick={() => setIsAddingLog(!isAddingLog)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center space-x-1 ${isAddingLog ? 'bg-gray-100 text-gray-600' : 'bg-red-600 text-white'}`}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isAddingLog ? "M6 18L18 6M6 6l12 12" : "M12 4v16m8-8H4"} /></svg>
                  <span>Log Event</span>
                </button>
              </div>

              {isAddingLog && (
                <form onSubmit={handleAddLogSubmit} className="bg-gray-50 p-4 rounded-xl border border-gray-200 space-y-3 mb-6 animate-slide-up">
                  <div className="grid grid-cols-2 gap-3">
                    <select 
                      className="text-sm p-2 rounded-lg border outline-none" 
                      value={newLog.type} 
                      onChange={e => setNewLog({...newLog, type: e.target.value as any, equipmentId: e.target.value === 'equipment' ? newLog.equipmentId : ''})}
                    >
                      <option value="note">General Note</option>
                      <option value="maintenance">Maintenance Entry</option>
                      <option value="status">Status Event</option>
                      <option value="equipment">Equipment Event</option>
                    </select>
                    <input type="date" required className="text-sm p-2 rounded-lg border outline-none" value={newLog.date} onChange={e => setNewLog({...newLog, date: e.target.value})} />

                    {newLog.type === 'equipment' && (
                      <select 
                        required
                        className="col-span-2 text-sm p-2 rounded-lg border outline-none focus:ring-2 focus:ring-red-500"
                        value={newLog.equipmentId}
                        onChange={e => setNewLog({...newLog, equipmentId: e.target.value})}
                      >
                        <option value="">Link to Equipment...</option>
                        {vehicle.equipment.map(eq => (
                          <option key={eq.id} value={eq.id}>{eq.name} (#{eq.id})</option>
                        ))}
                      </select>
                    )}

                    <textarea placeholder="Event description..." required className="col-span-2 text-sm p-2 rounded-lg border h-20" value={newLog.description} onChange={e => setNewLog({...newLog, description: e.target.value})} />
                  </div>
                  <button type="submit" className="w-full bg-red-600 text-white py-2 rounded-lg font-bold text-sm shadow-md transition-all active:scale-95">Add to Log</button>
                </form>
              )}

              <div className="relative">
                <div className="absolute left-4 top-0 bottom-0 w-0.5 bg-gray-100 ml-px" />
                <div className="space-y-8 relative">
                  {vehicle.history.map((entry) => (
                    <div key={entry.id} className="flex space-x-4">
                      <div className="relative z-10 shrink-0">{getHistoryIcon(entry.type)}</div>
                      <div className="flex-1 pt-0.5">
                        <div className="flex justify-between items-start mb-1">
                          <div className="flex items-center space-x-2">
                             <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{entry.date}</span>
                             {entry.equipmentId && (
                               <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-1.5 rounded-full border border-slate-200">
                                 Eq: #{entry.equipmentId}
                               </span>
                             )}
                          </div>
                          <span className={`text-[9px] font-black px-1.5 py-0.5 rounded uppercase ${entry.type === 'maintenance' ? 'bg-orange-50 text-orange-600' : entry.type === 'status' ? 'bg-blue-50 text-blue-600' : entry.type === 'equipment' ? 'bg-green-50 text-green-600' : 'bg-gray-50 text-gray-500'}`}>
                            {entry.type}
                          </span>
                        </div>
                        <p className="text-sm text-gray-800 leading-relaxed font-medium">{entry.description}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const TabButton: React.FC<{ active: boolean; onClick: () => void; label: string }> = ({ active, onClick, label }) => (
  <button onClick={onClick} className={`flex-1 min-w-[100px] py-4 text-xs font-bold uppercase tracking-wider transition-all whitespace-nowrap px-4 ${active ? 'text-red-600 border-b-2 border-red-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}>
    {label}
  </button>
);

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-gray-50 p-4 rounded-xl border border-transparent hover:border-gray-100 transition-colors">
    <span className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-base font-bold text-gray-900">{value}</span>
  </div>
);

const getConditionClass = (condition: Equipment['condition']) => {
  switch (condition) {
    case 'Good': return 'bg-green-100 text-green-700';
    case 'Fair': return 'bg-yellow-100 text-yellow-700';
    case 'Poor': return 'bg-orange-100 text-orange-700';
    case 'Needs Replacement': return 'bg-red-100 text-red-700';
    default: return 'bg-gray-100 text-gray-700';
  }
};

export default VehicleDetails;
